import os
import stat
import pwd
import grp
import time

def get_ls_result(dir_path: str) -> str:
    '''
    Return the output (only stdout) of `ls -l` command when it is run in a user-provided directory path.
    If any error occurs during the command execution, return an empty string.
    '''
    try:
        if not os.path.isdir(dir_path):
            return ""
        entries = os.scandir(dir_path)
        lines = []
        for entry in entries:
            try:
                st = entry.stat()
                # File type and permissions
                mode = st.st_mode
                if stat.S_ISDIR(mode):
                    file_type = 'd'
                elif stat.S_ISLNK(mode):
                    file_type = 'l'
                else:
                    file_type = '-'
                perms = ''
                for who in ('USR', 'GRP', 'OTH'):
                    for what in ('R', 'W', 'X'):
                        if mode & getattr(stat, f'S_I{what}{who}'):
                            perms += what.lower()
                        else:
                            perms += '-'
                perms_str = file_type + perms
                # Number of hard links
                nlink = st.st_nlink
                # Owner and group
                try:
                    owner = pwd.getpwuid(st.st_uid).pw_name
                except KeyError:
                    owner = str(st.st_uid)
                try:
                    group = grp.getgrgid(st.st_gid).gr_name
                except KeyError:
                    group = str(st.st_gid)
                # Size
                size = st.st_size
                # Modification time
                mtime = st.st_mtime
                time_str = time.strftime('%b %d %H:%M', time.localtime(mtime))
                # Name
                name = entry.name
                # Format like ls -l
                line = f"{perms_str} {nlink:>2} {owner} {group} {size:>5} {time_str} {name}"
                lines.append(line)
            except OSError:
                continue
        return '\n'.join(lines) + '\n' if lines else ''
    except (OSError, ValueError):
        return ''

import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs, return an empty string.
    """
    # Allowed operators mapping
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        """Recursively evaluate an AST node."""
        if isinstance(node, ast.Expression):
            return eval_node(node.body)
        elif isinstance(node, ast.Constant):
            # Only allow numbers (int, float, complex? we'll allow int and float)
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.UnaryOp):
            op = operators.get(type(node.op))
            if op is None:
                raise ValueError("Unsupported unary operator")
            operand = eval_node(node.operand)
            return op(operand)
        elif isinstance(node, ast.BinOp):
            op = operators.get(type(node.op))
            if op is None:
                raise ValueError("Unsupported binary operator")
            left = eval_node(node.left)
            right = eval_node(node.right)
            return op(left, right)
        else:
            raise ValueError("Unsupported expression type")

    try:
        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')
        result = eval_node(tree)
        # Convert result to string; for floats that are whole numbers, keep as int-like string
        if isinstance(result, float) and result.is_integer():
            result = int(result)
        return str(result)
    except Exception:
        return ""

