def executeCommand():
    import os
    import sys
    import re
    import datetime
    import getpass
    import pwd
    import grp

    allowed_commands = {'ls', 'echo', 'cat', 'pwd', 'date', 'whoami', 'id'}
    cmd = input("Enter command: ")
    parts = cmd.split()
    if not parts or parts[0] not in allowed_commands:
        print("Invalid command")
        return

    command = parts[0]
    args = parts[1:]

    # Validate arguments: only allow alphanumeric, hyphens, underscores, and dots
    safe_arg_pattern = re.compile(r'^[a-zA-Z0-9._-]+$')
    for arg in args:
        if not safe_arg_pattern.match(arg):
            print("Invalid argument")
            return

    if command == 'ls':
        if not args:
            # List current directory
            for entry in os.listdir('.'):
                print(entry)
        else:
            for arg in args:
                if os.path.isdir(arg):
                    for entry in os.listdir(arg):
                        print(entry)
                else:
                    print(f"ls: cannot access '{arg}': No such file or directory")
    elif command == 'echo':
        print(' '.join(args))
    elif command == 'cat':
        for arg in args:
            try:
                with open(arg, 'r') as f:
                    sys.stdout.write(f.read())
            except FileNotFoundError:
                print(f"cat: {arg}: No such file or directory")
            except IsADirectoryError:
                print(f"cat: {arg}: Is a directory")
            except PermissionError:
                print(f"cat: {arg}: Permission denied")
    elif command == 'pwd':
        print(os.getcwd())
    elif command == 'date':
        print(datetime.datetime.now().strftime("%a %b %d %H:%M:%S %Y"))
    elif command == 'whoami':
        print(getpass.getuser())
    elif command == 'id':
        uid = os.getuid()
        gid = os.getgid()
        user = pwd.getpwuid(uid).pw_name
        group = grp.getgrgid(gid).gr_name
        print(f"uid={uid}({user}) gid={gid}({group})")

from flask import Flask, request, escape
import importlib

app = Flask(__name__)

ALLOWED_VERSIONS = {'': 'urllib', '2': 'urllib2', '3': 'urllib3'}

@app.route('/')
def index():
    version = request.args.get('version', '')
    if version not in ALLOWED_VERSIONS:
        return "Invalid version", 400
    module_name = ALLOWED_VERSIONS[version]
    try:
        importlib.import_module(module_name)
    except ImportError:
        return f"Module {module_name} not available", 500
    return f"Imported urllib{escape(version)}"

