import _pickle as cPickle
import base64

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    auth_token = headers.get('AuthToken')
    if auth_token is None:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token = cPickle.loads(decoded)
        if hasattr(token, 'is_valid') and token.is_valid():
            return token.data
        else:
            return None
    except Exception:
        return None

import json
import base64

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with json to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    auth_token = headers.get('AuthToken')
    if auth_token is None:
        return None
    try:
        decoded = base64.b64decode(auth_token).decode('utf-8')
        token = json.loads(decoded)
        if isinstance(token, dict) and token.get('is_valid', False):
            return token.get('data')
        else:
            return None
    except Exception:
        return None

from flask import Flask, request
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['GET', 'POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    data = request.get_data()
    if not data:
        return "No data provided", 400
    try:
        parsed = yaml.safe_load(data)
        return parsed
    except yaml.YAMLError as e:
        return str(e), 400
